// Deep link parsed model
class DeepLinkData {
  final String path;
  final Map<String, String> parameters;
  final List<String> pathSegments;

  DeepLinkData({
    required this.path,
    required this.parameters,
    required this.pathSegments,
  });

  @override
  String toString() =>
      'DeepLinkData(path: $path, parameters: $parameters, pathSegments: $pathSegments)';
}

// Deep Link Handler singleton
class DeepLinkHandler {
  static final GlobalKey<NavigatorState> navigatorKey =
      GlobalKey<NavigatorState>();

  static final DeepLinkHandler _instance = DeepLinkHandler._internal();
  factory DeepLinkHandler() => _instance;
  DeepLinkHandler._internal();

  StreamSubscription? _linkSubscription;
  final StreamController<DeepLinkData> _deepLinkController =
      StreamController<DeepLinkData>.broadcast();

  Stream<DeepLinkData> get deepLinkStream => _deepLinkController.stream;

  /// Initialize deep link handling
  Future<void> init() async {
    // Handle initial link (app opened via deep link when not running)
    await _handleInitialLink();

    // Handle links when app is already running
    _linkSubscription = uriLinkStream.listen(
      (Uri? uri) {
        if (uri != null) {
          _processUri(uri);
        }
      },
      onError: (err) {
        debugPrint('Deep link error: $err');
      },
    );
  }

  Future<void> _handleInitialLink() async {
    try {
      final initialUri = await getInitialUri();
      if (initialUri != null) {
        // Delay slightly to ensure navigator is ready
        await Future.delayed(const Duration(milliseconds: 500));
        _processUri(initialUri);
      }
    } catch (e) {
      debugPrint('Failed to get initial link: $e');
    }
  }

  void _processUri(Uri uri) {
    debugPrint('Processing deep link: $uri');

    final deepLinkData = parseUri(uri);
    _deepLinkController.add(deepLinkData);
    _navigateToRoute(deepLinkData);
  }

  /// Parse a URI into DeepLinkData
  DeepLinkData parseUri(Uri uri) {
    // Handle myapp://profile/123?ref=campaign
    final path = uri.host + uri.path; // e.g., "profile/123"
    final pathSegments = <String>[uri.host, ...uri.pathSegments]
        .where((s) => s.isNotEmpty)
        .toList();
    final parameters = Map<String, String>.from(uri.queryParameters);

    // Also extract path-based parameters
    // e.g., myapp://profile/123 -> pathSegments = ['profile', '123']
    return DeepLinkData(
      path: path,
      parameters: parameters,
      pathSegments: pathSegments,
    );
  }

  /// Navigate based on parsed deep link data
  void _navigateToRoute(DeepLinkData data) {
    final navigator = navigatorKey.currentState;
    if (navigator == null) {
      debugPrint('Navigator not available for deep link navigation');
      return;
    }

    if (data.pathSegments.isEmpty) {
      debugPrint('No path segments in deep link');
      return;
    }

    final route = data.pathSegments[0];

    switch (route) {
      case 'profile':
        final userId = data.pathSegments.length > 1
            ? data.pathSegments[1]
            : data.parameters['id'];
        if (userId != null) {
          navigator.pushNamed(
            '/profile',
            arguments: ProfileArguments(
              userId: userId,
              referralSource: data.parameters['ref'],
              campaignId: data.parameters['campaign'],
            ),
          );
        } else {
          debugPrint('Profile deep link missing user ID');
        }
        break;

      case 'payment':
        final action = data.pathSegments.length > 1
            ? data.pathSegments[1]
            : data.parameters['action'];
        navigator.pushNamed(
          '/payment',
          arguments: PaymentArguments(
            action: action ?? 'default',
            transactionId: data.parameters['txn_id'],
            amount: data.parameters['amount'],
            currency: data.parameters['currency'] ?? 'USD',
            status: data.parameters['status'],
          ),
        );
        break;

      case 'product':
        final productId = data.pathSegments.length > 1
            ? data.pathSegments[1]
            : data.parameters['id'];
        navigator.pushNamed(
          '/product',
          arguments: ProductArguments(
            productId: productId ?? '',
            campaignId: data.parameters['campaign'],
            discount: data.parameters['discount'],
          ),
        );
        break;

      case 'promo':
        final promoCode = data.pathSegments.length > 1
            ? data.pathSegments[1]
            : data.parameters['code'];
        navigator.pushNamed(
          '/promo',
          arguments: PromoArguments(
            promoCode: promoCode ?? '',
            source: data.parameters['source'] ?? 'deeplink',
          ),
        );
        break;

      default:
        debugPrint('Unknown deep link route: $route');
        navigator.pushNamed('/not-found', arguments: data.path);
        break;
    }
  }

  void dispose() {
    _linkSubscription?.cancel();
    _deepLinkController.close();
  }
}

// Route arguments models
class ProfileArguments {
  final String userId;
  final String? referralSource;
  final String? campaignId;

  ProfileArguments({
    required this.userId,
    this.referralSource,
    this.campaignId,
  });
}

class PaymentArguments {
  final String action;
  final String? transactionId;
  final String? amount;
  final String currency;
  final String? status;

  PaymentArguments({
    required this.action,
    this.transactionId,
    this.amount,
    this.currency = 'USD',
    this.status,
  });
}

class ProductArguments {
  final String productId;
  final String? campaignId;
  final String? discount;

  ProductArguments({
    required this.productId,
    this.campaignId,
    this.discount,
  });
}

class PromoArguments {
