    this.source = 'deeplink',
  });
}

// Router
class AppRouter {
  static Route<dynamic> generateRoute(RouteSettings settings) {
    switch (settings.name) {
      case '/':
        return MaterialPageRoute(builder: (_) => const HomeScreen());

      case '/profile':
        final args = settings.arguments as ProfileArguments?;
        return MaterialPageRoute(
          builder: (_) => ProfileScreen(arguments: args),
        );

      case '/payment':
        final args = settings.arguments as PaymentArguments?;
        return MaterialPageRoute(
          builder: (_) => PaymentScreen(arguments: args),
        );

      case '/product':
        final args = settings.arguments as ProductArguments?;
        return MaterialPageRoute(
          builder: (_) => ProductScreen(arguments: args),
        );

      case '/promo':
        final args = settings.arguments as PromoArguments?;
        return MaterialPageRoute(
          builder: (_) => PromoScreen(arguments: args),
        );

      case '/not-found':
        final path = settings.arguments as String? ?? 'unknown';
        return MaterialPageRoute(
          builder: (_) => NotFoundScreen(path: path),
        );

      default:
        return MaterialPageRoute(
          builder: (_) => NotFoundScreen(path: settings.name ?? 'unknown'),
        );
    }
  }
}

// Wrapper widget that initializes deep link handling
class DeepLinkWrapper extends StatefulWidget {
  const DeepLinkWrapper({super.key});

  @override
  State<DeepLinkWrapper> createState() => _DeepLinkWrapperState();
}

class _DeepLinkWrapperState extends State<DeepLinkWrapper> {
  final DeepLinkHandler _deepLinkHandler = DeepLinkHandler();
  StreamSubscription<DeepLinkData>? _deepLinkSubscription;
  String _lastDeepLink = 'None';

  @override
  void initState() {
    super.initState();
    _deepLinkHandler.init();

    _deepLinkSubscription = _deepLinkHandler.deepLinkStream.listen((data) {
      setState(() {
        _lastDeepLink = data.toString();
      });
    });
  }

  @override
  void dispose() {
    _deepLinkSubscription?.cancel();
    _deepLinkHandler.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return HomeScreen(lastDeepLink: _lastDeepLink);
  }
}

